def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            if item > 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        complex_score = 0
        if ratio > 2:
            for p in range(1, 5):
                partial = 0
                for q in range(1, p+2):
                    partial += ((-1)**q) * (ratio**(p*q)) / (q*p + 1)
                complex_score += partial / p
            priorities[i] = complex_score + np.exp(ratio) / (ratio + 1)
        elif 1 < ratio <= 2:
            base = ratio ** 4
            penalty = 0
            for a in range(1, 4):
                for b in range(1, 4):
                    if a != b:
                        penalty += (ratio ** (a+b)) / (a * b)
            priorities[i] = base + penalty
        elif 0 < ratio <= 1:
            val = 0
            for j in range(1, 8):
                sign = (-1) ** (j+1)
                val += sign * (ratio ** (2*j - 1)) / (j * 3)
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 7
            priorities[i] = abs(val) * multiplier
            if 0.7 < ratio < 1:
                extra_sum = 0
                for m in range(1, 6):
                    extra_sum += (ratio ** m) / (m * (m+1))
                priorities[i] += extra_sum * (1 + np.sin(ratio * np.pi))
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf:
            adjust = 0
            for z in range(1, 4):
                adjust += ((-1)**z) * np.log1p(ratio*z) / z
            priorities[i] += adjust * (0.5 if item < capacity else 1.5)
            if i % 2 == 0:
                priorities[i] *= 1.1
            else:
                priorities[i] *= 0.9
    return priorities
